import React, { useState, useEffect, useContext } from 'react';
import api from '../utils/api';
import { AuthContext } from '../context/AuthContext';
import { Link } from 'react-router-dom';
import './WorkerDashboardNew.css';

const WorkerDashboard = () => {
  const { user } = useContext(AuthContext);
  const [activePage, setActivePage] = useState('dashboard');
  const [activeTab, setActiveTab] = useState('available');
  const [jobs, setJobs] = useState([]);
  const [myJobs, setMyJobs] = useState([]);
  const [earnings, setEarnings] = useState(null);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');
  const [appliedJobs, setAppliedJobs] = useState(new Set());
  const [applyingJobId, setApplyingJobId] = useState(null);
  const [profileData, setProfileData] = useState(user || {});
  const [isEditing, setIsEditing] = useState(false);
  const [monthlyEarnings, setMonthlyEarnings] = useState({});

  const categories = [
    { id: 'all', label: 'All Jobs', icon: '📋' },
    { id: 'painting', label: 'Painting', icon: '🎨' },
    { id: 'electrical', label: 'Electrical', icon: '⚡' },
    { id: 'masonry', label: 'Masonry', icon: '🧱' },
    { id: 'plumbing', label: 'Plumbing', icon: '🚰' },
    { id: 'carpentry', label: 'Carpentry', icon: '🪚' },
    { id: 'welding', label: 'Welding', icon: '🔥' },
    { id: 'construction', label: 'Construction', icon: '🏗️' },
    { id: 'cleaning', label: 'Cleaning', icon: '🧹' },
    { id: 'gardening', label: 'Gardening', icon: '🌱' },
    { id: 'loading', label: 'Loading', icon: '📦' },
    { id: 'fabrication', label: 'Fabrication', icon: '🛠️' },
    { id: 'tiling', label: 'Tiling', icon: '📐' }
  ];

  const handleApplyJob = async (jobId) => {
    try {
      setApplyingJobId(jobId);
      const response = await api.post(`/jobs/${jobId}/accept`, {
        proposedRate: undefined,
        message: 'Interested in this job'
      });

      if (response.data.success) {
        setAppliedJobs(new Set([...appliedJobs, jobId]));
        alert('✅ Job application submitted successfully!');
      }
    } catch (error) {
      alert('❌ ' + (error.response?.data?.message || 'Failed to apply for job'));
    } finally {
      setApplyingJobId(null);
    }
  };

  const handleSaveProfile = async () => {
    try {
      const response = await api.put('/workers/profile', profileData);
      if (response.data.success) {
        alert('✅ Profile updated successfully!');
        setIsEditing(false);
      }
    } catch (error) {
      alert('❌ Error updating profile: ' + (error.response?.data?.message || 'Unknown error'));
    }
  };

  const handleProfileChange = (field, value) => {
    // Handle nested properties (e.g., 'location.city')
    if (field.includes('.')) {
      const [parent, child] = field.split('.');
      setProfileData({
        ...profileData,
        [parent]: {
          ...(profileData[parent] || {}),
          [child]: value
        }
      });
    } else {
      setProfileData({
        ...profileData,
        [field]: value
      });
    }
  };

  useEffect(() => {
    const fetchDashboardData = async () => {
      try {
        setLoading(true);
        const query = filter !== 'all' ? `?category=${filter}` : '';
        const [jobsRes, myJobsRes, earningsRes] = await Promise.all([
          api.get(`/workers/available-jobs${query}`),
          api.get('/workers/my-jobs?status=assigned'),
          api.get('/workers/earnings')
        ]);
        setJobs(jobsRes.data.jobs);
        setMyJobs(myJobsRes.data.jobs);
        setEarnings(earningsRes.data.earnings);
        setMonthlyEarnings(earningsRes.data.earnings?.monthlyBreakdown || {});
      } catch (error) {
        console.error('Error fetching dashboard data:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchDashboardData();
  }, [filter, activePage]);

  const renderDashboardPage = () => {
    return (
      <div className="dashboard-page">
        <div className="page-header">
          <h1>Welcome, {user?.name}! 👋</h1>
        </div>

        <div className="stats-section">
          <div className="stat-card">
            <div className="stat-icon">💵</div>
            <div className="stat-content">
              <h4>Total Earnings</h4>
              <p className="stat-value">₹{earnings?.total || 0}</p>
            </div>
          </div>
          <div className="stat-card">
            <div className="stat-icon">🎯</div>
            <div className="stat-content">
              <h4>Jobs Completed</h4>
              <p className="stat-value">{earnings?.completedJobs || 0}</p>
            </div>
          </div>
          <div className="stat-card">
            <div className="stat-icon">⏳</div>
            <div className="stat-content">
              <h4>Pending Payments</h4>
              <p className="stat-value">₹{earnings?.pendingPayments || 0}</p>
            </div>
          </div>
        </div>

        <div className="tabs-section">
          <div className="tab-buttons">
            <button 
              className={`tab-btn ${activeTab === 'active' ? 'active' : ''}`}
              onClick={() => setActiveTab('active')}
            >
              🏢 Active Jobs ({myJobs.length})
            </button>
            <button 
              className={`tab-btn ${activeTab === 'available' ? 'active' : ''}`}
              onClick={() => setActiveTab('available')}
            >
              🔍 Available Jobs ({jobs.length})
            </button>
          </div>
        </div>

        {activeTab === 'active' ? (
          <div className="tab-section">
            <div className="section-header">
              <h2>Your Active Jobs</h2>
              <p className="section-subtitle">{myJobs.length} job{myJobs.length !== 1 ? 's' : ''} in progress</p>
            </div>
            {myJobs.length > 0 ? (
              <div className="jobs-list">
                {myJobs.map(job => (
                  <div key={job._id} className="job-card active-job">
                    <div className="job-badge">ACTIVE</div>
                    <div className="job-info">
                      <h3>{job.title}</h3>
                      <p className="job-category">{job.category}</p>
                      <p className="job-employer">👤 {job.employer?.name}</p>
                      <p className="job-location">📍 {job.location?.city}, {job.location?.district}</p>
                      <div className="job-meta">
                        <span>⏱️ Duration: {job.duration?.estimated} {job.duration?.unit}</span>
                      </div>
                    </div>
                    <div className="job-action">
                      <p className="job-price">₹{job.wageCalculation?.totalEstimated}</p>
                      <Link to={`/job/${job._id}`} className="view-btn">View Details</Link>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="empty-state">
                <p>No active jobs right now</p>
              </div>
            )}
          </div>
        ) : (
          <div className="tab-section">
            <div className="filter-section">
              <h3><span>🔍</span> Filter by Category</h3>
              <div className="filter-scroll">
                {categories.map(cat => (
                  <button 
                    key={cat.id} 
                    className={`filter-btn ${filter === cat.id ? 'active' : ''}`}
                    onClick={() => setFilter(cat.id)}
                  >
                    <span className="filter-icon">{cat.icon}</span>
                    <span className="filter-label">{cat.label}</span>
                  </button>
                ))}
              </div>
            </div>

            <div className="section-header">
              <h2>Available Jobs for You</h2>
              <p className="section-subtitle">{jobs.length} job{jobs.length !== 1 ? 's' : ''} found</p>
            </div>
            
            {jobs.length > 0 ? (
              <div className="jobs-list">
                {jobs.map(job => (
                  <div key={job._id} className="job-card available-job">
                    <div className="job-header">
                      <h3>{job.title}</h3>
                      <span className={`urgency-badge ${job.urgency}`}>🔴 {job.urgency.toUpperCase()}</span>
                    </div>
                    <p className="job-category">Category: {job.category}</p>
                    <p className="job-employer">👤 Posted by: {job.employer?.name}</p>
                    <p className="job-location">📍 {job.location?.city}, {job.location?.address}</p>
                    <div className="job-details">
                      <div className="detail-item">
                        <span className="label">⏱️ Duration:</span>
                        <span className="value">{job.duration?.estimated} {job.duration?.unit}</span>
                      </div>
                      <div className="detail-item">
                        <span className="label">💰 Estimated Pay:</span>
                        <span className="value price">₹{job.wageCalculation?.totalEstimated}</span>
                      </div>
                    </div>
                    <p className="job-description">{job.description?.substring(0, 100)}...</p>
                    <div className="job-action-buttons">
                      <button 
                        className="apply-btn"
                        onClick={() => handleApplyJob(job._id)}
                        disabled={appliedJobs.has(job._id) || applyingJobId === job._id}
                      >
                        {appliedJobs.has(job._id) ? '✅ Applied' : (applyingJobId === job._id ? '⏳ Applying...' : '📝 Apply Now')}
                      </button>
                      <Link to={`/job/${job._id}`} className="view-btn-large">View Details</Link>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="empty-state">
                <p>No jobs found matching your skills right now.</p>
                <p className="empty-hint">Check back later or explore other categories!</p>
              </div>
            )}
          </div>
        )}
      </div>
    );
  };

  const renderHistoryPage = () => {
    return (
      <div className="history-page">
        <div className="page-header">
          <h1>📊 Work History & Earnings</h1>
        </div>

        <div className="earnings-summary">
          <div className="earn-card">
            <h3>💰 Total Earnings</h3>
            <p className="earn-value">₹{earnings?.total || 0}</p>
          </div>
          <div className="earn-card">
            <h3>✅ Jobs Completed</h3>
            <p className="earn-value">{earnings?.completedJobs || 0}</p>
          </div>
          <div className="earn-card">
            <h3>⏳ Pending Payments</h3>
            <p className="earn-value">₹{earnings?.pendingPayments || 0}</p>
          </div>
        </div>

        <div className="monthly-breakdown">
          <h3>📅 Monthly Earnings Breakdown</h3>
          <div className="earnings-table">
            {Object.keys(monthlyEarnings).length > 0 ? (
              <table>
                <thead>
                  <tr>
                    <th>Month</th>
                    <th>Earnings</th>
                  </tr>
                </thead>
                <tbody>
                  {Object.entries(monthlyEarnings).map(([month, amount]) => (
                    <tr key={month}>
                      <td>{month}</td>
                      <td className="amount">₹{amount}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            ) : (
              <p className="no-data">No earnings history yet</p>
            )}
          </div>
        </div>
      </div>
    );
  };

  const renderSettingsPage = () => {
    return (
      <div className="settings-page">
        <div className="page-header">
          <h1>⚙️ Account Settings</h1>
        </div>

        <div className="settings-container">
          <div className="settings-section">
            <h2>👤 Personal Information</h2>
            {isEditing ? (
              <div className="edit-form">
                <div className="form-group">
                  <label>👤 Full Name</label>
                  <input 
                    type="text" 
                    value={profileData.name || ''}
                    onChange={(e) => handleProfileChange('name', e.target.value)}
                  />
                </div>
                <div className="form-group">
                  <label>📞 Phone Number</label>
                  <input 
                    type="text" 
                    value={profileData.phone || ''}
                    onChange={(e) => handleProfileChange('phone', e.target.value)}
                  />
                </div>
                <div className="form-group">
                  <label>📝 Bio/Description</label>
                  <textarea 
                    value={profileData.bio || ''}
                    onChange={(e) => handleProfileChange('bio', e.target.value)}
                    rows="4"
                    placeholder="Tell employers about yourself..."
                  />
                </div>
                <div className="form-actions">
                  <button className="save-btn" onClick={handleSaveProfile}>✅ Save Changes</button>
                  <button className="cancel-btn" onClick={() => setIsEditing(false)}>✖️ Cancel</button>
                </div>
              </div>
            ) : (
              <div className="profile-view">
                <div className="info-row">
                  <span className="label">👤 Name:</span>
                  <span className="value">{profileData.name}</span>
                </div>
                <div className="info-row">
                  <span className="label">📞 Phone:</span>
                  <span className="value">{profileData.phone}</span>
                </div>
                <div className="info-row">
                  <span className="label">📧 Email:</span>
                  <span className="value">{profileData.email}</span>
                </div>
                <div className="info-row">
                  <span className="label">📝 Bio:</span>
                  <span className="value">{profileData.bio || 'Not set'}</span>
                </div>
                <button className="edit-btn" onClick={() => setIsEditing(true)}>✏️ Edit Profile</button>
              </div>
            )}
          </div>

          <div className="settings-section">
            <h2>📍 Location Details</h2>
            {isEditing ? (
              <div className="edit-form">
                <div className="form-group">
                  <label>📍 Full Address</label>
                  <input 
                    type="text" 
                    value={profileData.location?.address || ''}
                    onChange={(e) => handleProfileChange('location.address', e.target.value)}
                  />
                </div>
                <div className="form-group">
                  <label>🏙️ City</label>
                  <input 
                    type="text" 
                    value={profileData.location?.city || ''}
                    onChange={(e) => handleProfileChange('location.city', e.target.value)}
                  />
                </div>
                <div className="form-group">
                  <label>📌 District</label>
                  <input 
                    type="text" 
                    value={profileData.location?.district || ''}
                    onChange={(e) => handleProfileChange('location.district', e.target.value)}
                  />
                </div>
                <div className="form-group">
                  <label>🗺️ State</label>
                  <input 
                    type="text" 
                    value={profileData.location?.state || ''}
                    onChange={(e) => handleProfileChange('location.state', e.target.value)}
                  />
                </div>
                <div className="form-group">
                  <label>📮 Pincode</label>
                  <input 
                    type="text" 
                    value={profileData.location?.pincode || ''}
                    onChange={(e) => handleProfileChange('location.pincode', e.target.value)}
                  />
                </div>
              </div>
            ) : (
              <div className="location-view">
                <div className="info-row">
                  <span className="label">📍 Address:</span>
                  <span className="value">{profileData.location?.address || 'Not set'}</span>
                </div>
                <div className="info-row">
                  <span className="label">🏙️ City:</span>
                  <span className="value">{profileData.location?.city || 'Not set'}</span>
                </div>
                <div className="info-row">
                  <span className="label">📌 District:</span>
                  <span className="value">{profileData.location?.district || 'Not set'}</span>
                </div>
                <div className="info-row">
                  <span className="label">🗺️ State:</span>
                  <span className="value">{profileData.location?.state || 'Not set'}</span>
                </div>
                <div className="info-row">
                  <span className="label">📮 Pincode:</span>
                  <span className="value">{profileData.location?.pincode || 'Not set'}</span>
                </div>
              </div>
            )}
          </div>

          <div className="settings-section">
            <h2>🔧 Account Status</h2>
            {isEditing ? (
              <div className="edit-form">
                <div className="form-group">
                  <label>🛠️ Skills (comma separated)</label>
                  <input 
                    type="text" 
                    value={profileData.skills?.join(', ') || ''}
                    onChange={(e) => handleProfileChange('skills', e.target.value.split(',').map(skill => skill.trim()))}
                    placeholder="e.g., painting, electrical, plumbing"
                  />
                </div>
                <div className="form-group">
                  <label>📊 Expert Level</label>
                  <select 
                    value={profileData.expertLevel || 'beginner'}
                    onChange={(e) => handleProfileChange('expertLevel', e.target.value)}
                  >
                    <option value="beginner">Beginner</option>
                    <option value="intermediate">Intermediate</option>
                    <option value="expert">Expert</option>
                  </select>
                </div>
                <div className="form-group">
                  <label>⏱️ Availability Status</label>
                  <select 
                    value={profileData.availability?.status || 'available'}
                    onChange={(e) => handleProfileChange('availability.status', e.target.value)}
                  >
                    <option value="available">Available</option>
                    <option value="busy">Busy</option>
                    <option value="unavailable">Unavailable</option>
                  </select>
                </div>
                <div className="form-group">
                  <label>💰 Expected Daily Rate (₹)</label>
                  <input 
                    type="number" 
                    value={profileData.expectedDailyRate || ''}
                    onChange={(e) => handleProfileChange('expectedDailyRate', parseFloat(e.target.value) || 0)}
                    placeholder="Your expected daily wage"
                  />
                </div>
              </div>
            ) : (
              <div className="status-view">
                <div className="status-item">
                  <span>🛠️ Skills:</span>
                  <span className="skills-list">{profileData.skills?.join(', ') || 'Not set'}</span>
                </div>
                <div className="status-item">
                  <span>📊 Expert Level:</span>
                  <span className="level-badge">{profileData.expertLevel}</span>
                </div>
                <div className="status-item">
                  <span>⏱️ Status:</span>
                  <span className="status-badge available">{profileData.availability?.status || 'available'}</span>
                </div>
                <div className="status-item">
                  <span>⭐ Rating:</span>
                  <span className="rating">{profileData.rating?.average || 0} ⭐ ({profileData.rating?.count || 0} reviews)</span>
                </div>
                <div className="status-item">
                  <span>💰 Expected Daily Rate:</span>
                  <span className="rate">₹{profileData.expectedDailyRate || 'Not set'}</span>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  };

  if (loading) return <div className="loading">Loading dashboard...</div>;

  return (
    <div className="worker-dashboard-new">
      {/* Sidebar Navigation */}
      <aside className="worker-sidebar">
        <div className="sidebar-header">
          <div className="worker-avatar">
            {user?.name?.charAt(0) || 'W'}
          </div>
          <h3>{user?.name}</h3>
          <p>Worker</p>
        </div>

        <nav className="sidebar-nav">
          <button 
            className={`nav-item ${activePage === 'dashboard' ? 'active' : ''}`}
            onClick={() => setActivePage('dashboard')}
          >
            <span className="nav-icon">📊</span> Dashboard
          </button>
          <button 
            className={`nav-item ${activePage === 'active' ? 'active' : ''}`}
            onClick={() => setActivePage('active')}
          >
            <span className="nav-icon">🏢</span> Active Jobs ({myJobs.length})
          </button>
          <button 
            className={`nav-item ${activePage === 'history' ? 'active' : ''}`}
            onClick={() => setActivePage('history')}
          >
            <span className="nav-icon">📋</span> History
          </button>
          <button 
            className={`nav-item ${activePage === 'settings' ? 'active' : ''}`}
            onClick={() => setActivePage('settings')}
          >
            <span className="nav-icon">⚙️</span> Settings
          </button>
        </nav>
      </aside>

      {/* Main Content */}
      <main className="worker-main-content">
        {activePage === 'dashboard' && renderDashboardPage()}
        {activePage === 'active' && (
          <div className="active-jobs-page">
            <div className="page-header">
              <h1>🏢 Active Jobs</h1>
            </div>
            {myJobs.length > 0 ? (
              <div className="jobs-list">
                {myJobs.map(job => (
                  <div key={job._id} className="job-card active-job">
                    <div className="job-badge">ACTIVE</div>
                    <div className="job-info">
                      <h3>{job.title}</h3>
                      <p className="job-category">{job.category}</p>
                      <p className="job-employer">👤 {job.employer?.name}</p>
                      <p className="job-location">📍 {job.location?.city}</p>
                    </div>
                    <div className="job-action">
                      <p className="job-price">₹{job.wageCalculation?.totalEstimated}</p>
                      <Link to={`/job/${job._id}`} className="view-btn">View Details</Link>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="empty-state">
                <p>No active jobs</p>
              </div>
            )}
          </div>
        )}
        {activePage === 'history' && renderHistoryPage()}
        {activePage === 'settings' && renderSettingsPage()}
      </main>
    </div>
  );
};

export default WorkerDashboard;
